tasks.implementationGuide:
types/meeting.ts:
- type MeetingStatus = 'active' | 'cancelled'
- type ApprovalType = 'auto' | 'manual'
- interface Meeting { id, host_id, title, description, date_time, location, max_participants, fee, approval_type: ApprovalType, status: MeetingStatus, invite_token, carpool_enabled, created_at, updated_at }

types/notice.ts:
- interface Notice { id, meeting_id, author_id, title, content, is_pinned, created_at, updated_at }

types/participation.ts:
- type ParticipationStatus = 'pending' | 'approved' | 'rejected' | 'waitlisted'
- interface Participation { id, meeting_id, user_id, status: ParticipationStatus, waitlist_order, created_at, updated_at }

types/carpool.ts:
- type CarpoolPassengerStatus = 'pending' | 'accepted' | 'rejected'
- interface CarpoolDriver { id, meeting_id, driver_id, departure_location, available_seats, departure_time, created_at, updated_at }
- interface CarpoolPassenger { id, driver_id, passenger_id, status: CarpoolPassengerStatus, created_at, updated_at }

types/settlement.ts:
- type SettlementType = 'equal' | 'manual'
- interface Settlement { id, meeting_id, created_by, total_amount, settlement_type: SettlementType, created_at, updated_at }
- interface SettlementItem { id, settlement_id, description, amount }
- interface SettlementParticipant { id, settlement_id, user_id, amount, is_paid, created_at, updated_at }

types/index.ts:
- 모든 타입 re-export

lib/validations/meeting.ts:
- meetingSchema = z.object({ title: z.string().min(1), description: z.string().optional(), date_time: z.string().min(1), location: z.string().min(1), max_participants: z.number().min(1).max(100), fee: z.number().min(0).optional(), approval_type: z.union([z.literal('auto'), z.literal('manual')]) })
- type MeetingFormValues = z.infer<typeof meetingSchema>

lib/validations/notice.ts:
- noticeSchema = z.object({ title: z.string().min(1), content: z.string().min(1), is_pinned: z.boolean().default(false) })
- type NoticeFormValues = z.infer<typeof noticeSchema>
